INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L2_A', 'P2a', 2, 'A', 'Data recording', NULL, 'Say: ''I am going to name some animals: Dog, Cat, Dog, Bird, Dog, Cat. Make a list showing how many of each animal I said.''', 'Child correctly records 3 Dogs, 2 Cats, 1 Bird using numbers, tally marks, or pictures.', 'Child misses an animal or counts incorrectly.', 'How can you check if your total matches the number of animals I named?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L2_B', 'P2a', 2, 'B', 'Data recording', NULL, 'Show a picture with various shapes (e.g., 4 circles, 3 squares, 5 triangles). Say: ''Make a table to show how many of each shape there are.''', 'Child creates a basic table or list correctly identifying the quantities of each shape.', 'Child miscounts or organizes the data in a confusing way.', 'If I add one more square to the picture, how do you change your table?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L2_C', 'P2a', 2, 'C', 'Data recording', NULL, 'Say: ''Look at your bookshelf or a stack of books. Count how many are thick and how many are thin. Write it down.''', 'Child correctly categorizes and counts the books based on the given constraint.', 'Child counts all books together without categorizing.', 'What rule did you use to decide if a book was thick or thin?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L3_A', 'P2a', 3, 'A', 'Error detection', NULL, 'Show a list: ''Dogs: 3, Cats: 2, Dogs: 1''. Say: ''My friend counted pets, but their list looks funny. What is wrong with how they recorded the data?''', 'Child points out that ''Dogs'' should be combined into a single total of 4.', 'Child doesn''t see a problem with having multiple entries for the same category.', 'Why is it confusing to have ''Dogs'' written in two different places on a list?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L3_B', 'P2a', 3, 'B', 'Error detection', NULL, 'Say: ''I asked 5 people their favorite fruit. Here is my data: 2 said Apple, 2 said Banana. What is wrong?''', 'Child realizes the total only adds up to 4, so one person''s answer is missing.', 'Child thinks the data is fine.', 'If you know how many people you asked, how can you check if your data is complete?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L3_C', 'P2a', 3, 'C', 'Error detection', NULL, 'Say: ''I want to know the most popular game in your class. I only asked my 2 best friends. Is this a good way to find out what the WHOLE class likes? Why?''', 'Child explains that 2 people do not represent the whole class.', 'Child thinks asking friends is sufficient.', 'Who else should you ask to get a better answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L4_A', 'P2a', 4, 'A', 'Design and Justification', NULL, 'Say: ''Design a survey to find out what we should have for dinner tomorrow. Tell me exactly what question you will ask and how you will record the answers.''', 'Child proposes a clear question (e.g., ''Do you want pizza or pasta?'') and a method to record votes.', 'Child just picks a dinner without surveying, or has no plan for recording.', 'If someone changes their mind, how will you fix your data?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L4_B', 'P2a', 4, 'B', 'Design and Justification', NULL, 'Say: ''Invent a way to keep track of how many glasses of water you drink today without using numbers.''', 'Child suggests drawing tally marks, moving a pebble for each glass, or coloring sections of a paper.', 'Child insists on using numbers, or cannot think of an alternative tracking method.', 'How will you know the total at the end of the day using your method?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L4_C', 'P2a', 4, 'C', 'Design and Justification', NULL, 'Say: ''You need to figure out which drawer in the kitchen has the most things in it. Tell me your step-by-step plan.''', 'Child explains a process of opening each drawer, counting the items, writing down the total for each, and then comparing the numbers.', 'Child guesses based on drawer size, or doesn''t include a recording step.', 'Why is it important to write the numbers down instead of just trying to remember them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L4_M', 'P2a', 4, 'M', 'Real-world situation', NULL, 'We are going to the store to buy snacks for the family movie night. How do we make sure we get something everyone actually wants to eat, without just guessing?', 'Child suggests asking everyone what they want and writing it down (taking a survey/collecting data).', 'Child just lists things they personally like, or says ''buy everything''.', 'If two people want the same thing, how do we make sure we get enough?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L1_A', 'P2b', 1, 'A', 'Physical bar graph', 'Blocks, books', 'Put 3 red blocks, 5 blue blocks, and 2 yellow blocks on the table. Say: ''Stack the blocks by color to see which color makes the tallest tower.''', 'Child physically stacks the blocks and visually compares the heights.', 'Child mixes the colors, or can''t see the connection between tower height and quantity.', 'Without counting the blocks, which color has the most? How do you know?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L1_B', 'P2b', 1, 'B', 'Physical tally marks', 'Popsicle sticks, pencils', 'Give the child a bunch of sticks. Say: ''We need to count these. Put down one stick for every finger on one hand. Then put another stick across them. This is a group of 5.''', 'Child arranges sticks into a tally group of 4 straight lines and 1 diagonal line.', 'Child makes a group of 5 parallel lines, or random piles.', 'Why is grouping sticks like this faster than just putting them in a straight line?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L1_C', 'P2b', 1, 'C', 'Physical bar graph', 'Coins, buttons', 'Say: ''Line up all the big coins in a row starting at this line. Now line up the small coins next to them. Let''s see which line goes further.''', 'Child creates parallel lines of objects to compare lengths visually.', 'Child makes lines of unequal starting points or spaces the items inconsistently.', 'Why do the lines need to start at exactly the same place to be fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L2_A', 'P2b', 2, 'A', 'Tally reading', NULL, 'Show a picture of tally marks (e.g., 3 groups of five, plus 2). Say: ''How many marks are here?''', 'Child correctly identifies the tally marks representing 17, preferably by counting 5, 10, 15, 16, 17.', 'Child counts every single mark by 1s, or misinterprets the cross line.', 'How does the slanted line help you count faster?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L2_B', 'P2b', 2, 'B', 'Graph reading', NULL, 'Show a simple bar graph (e.g., Cats: 4, Dogs: 6). Say: ''Look at the bar for Dogs. How many people chose Dogs?''', 'Child correctly reads the value 6 from the axis aligned with the top of the bar.', 'Child guesses, or counts the boxes incorrectly if there''s a scale.', 'How do you use the numbers on the side to find out how tall the bar is?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L2_C', 'P2b', 2, 'C', 'Graph creation', NULL, 'Say: ''I have 3 red apples and 5 green apples. Draw a bar graph to show this. Make sure the bars start at the bottom.''', 'Child draws two bars, labeling one Red and one Green, with the Green bar noticeably taller.', 'Child draws the bars sideways or floating, or makes them the same height.', 'If I get 3 more red apples, what will you have to do to your drawing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L3_A', 'P2b', 3, 'A', 'Error detection', NULL, 'Show a bar graph where the numbers on the side skip around (1, 5, 2, 8). Say: ''What is wrong with the numbers on the side of this graph?''', 'Child identifies that the scale is out of order, making the bar heights meaningless.', 'Child thinks the numbers just show the exact values of the bars.', 'Why must the numbers on the side go in order like a ruler?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L3_B', 'P2b', 3, 'B', 'Error detection', NULL, 'Show tally marks: IIII I. Say: ''My friend tried to make a group of 5, but didn''t put the line across. Is this still 5?''', 'Child understands it represents 5 items, but points out it''s not the correct way to make a tally bundle for easy counting.', 'Child thinks it represents 6, or that it''s wrong because it doesn''t look like a bundle.', 'If you have a lot of marks, why is it better to put the line across instead of just leaving a space?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L3_C', 'P2b', 3, 'C', 'Error detection', NULL, 'Show two bar graphs. Graph 1 has a tall bar for 3 (each line is 1). Graph 2 has a short bar for 50 (each line is 10). Say: ''Which number is bigger? But which bar is taller? Why?''', 'Child explains that the tallness depends on the numbers on the side (the scale), not just the number of items.', 'Child insists the taller bar always means more items.', 'If you want to trick someone into thinking 3 is bigger than 50, how would you draw the graph?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_A', 'P2b', 4, 'A', 'Design and Justification', NULL, 'Say: ''Create a tally chart to show how many shirts, pants, and socks you are wearing right now.''', 'Child correctly identifies and records the quantities using tally marks.', 'Child uses numbers instead of tallies, or miscounts.', 'If you put on a jacket, how would you update your chart?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_B', 'P2b', 4, 'B', 'Design and Justification', NULL, 'Say: ''I want you to make a bar graph showing the favorite colors of 4 imaginary friends. You decide the colors and the numbers. Make sure one color is a tie with another.''', 'Child creates a complete graph with labels, an ordered scale, and two bars of equal height.', 'Child forgets labels, scale, or doesn''t include a tie.', 'How can someone tell just by looking at the graph that there is a tie, without reading the numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_C', 'P2b', 4, 'C', 'Design and Justification', NULL, 'Say: ''Teach me how to read a bar graph using a drawing of two towers.''', 'Child explains that the taller tower means more, and shows how to check the numbers on the side.', 'Child just says ''the big one wins'' without explaining how to read the actual values.', 'What do the words at the bottom of the towers tell us?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2b_L4_M', 'P2b', 4, 'M', 'Real-world situation', NULL, 'You are counting passing cars: 12 red, 15 blue, and 8 white. What is the fastest way to write this down quickly while they drive by, so you don''t lose count?', 'Child suggests using tally marks.', 'Child suggests writing full words or trying to remember them all.', 'Why are tally marks faster than writing the number ''12'' and then erasing it to write ''13''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L1_A', 'P2c', 1, 'A', 'Physical matching', '3 different items (e.g., shoe, spoon, book), 3 sticky notes (labels)', 'Put the items out with sticky notes saying: ''Size 6'', ''Silver'', ''100 pages''. Ask: ''Which question goes with each item? A) How long is it to read? B) What color is it? C) Will it fit my foot?''', 'Child correctly matches the item, its property, and the corresponding question.', 'Child mismatches properties and items, or cannot identify the correct question.', 'Why does ''100 pages'' answer ''How long is it to read'' and not ''Will it fit my foot''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L1_B', 'P2c', 1, 'B', 'Physical data translation', 'A small pile of 4 rocks and 2 leaves', 'Show the pile. Say: ''I have 4 rocks and 2 leaves. What is a question you could ask where the answer is 4?''', 'Child asks a question like ''How many rocks are there?''', 'Child asks ''How many leaves?'' or ''What are these?''', 'If the answer was 6, what question would you have asked?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L1_C', 'P2c', 1, 'C', 'Physical data translation', 'A jar of water', 'Hold up the jar. Say: ''The answer is "Half full." What was the question?''', 'Child asks ''How full is the jar?'' or ''How much water is in the jar?''', 'Child asks ''Is it water?'' or ''Is it empty?''', 'If the answer was ''Water,'' what would the question be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L2_A', 'P2c', 2, 'A', 'Question identification', NULL, 'Say: ''Here is some data: 12 people took the bus, 5 people walked, 3 people rode bikes. Which of these questions does this data answer? A) What is the most popular color? B) How do people get to work? C) How many cars are there?''', 'Child correctly identifies option B.', 'Child chooses A or C.', 'Why doesn''t this data answer question C?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L2_B', 'P2c', 2, 'B', 'Question generation', NULL, 'Say: ''The answer is 7. The data is: 3 boys and 4 girls. What is the question?''', 'Child formulates a question like ''How many children are there in total?''', 'Child asks ''How many girls?'' or doesn''t use the provided data.', 'How did you know the question was asking for the total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L2_C', 'P2c', 2, 'C', 'Question identification', NULL, 'Show a simple bar graph with only two bars: ''Apples (6)'' and ''Oranges (4)''. Say: ''Tell me two different questions this graph can answer.''', 'Child asks ''Which fruit is more popular?'' and ''How many people like apples?'' or similar.', 'Child asks questions not covered by the graph, like ''Are the apples red?''', 'Can this graph tell us if they liked bananas? Why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L3_A', 'P2c', 3, 'A', 'Error detection', NULL, 'Say: ''My friend collected data on the ages of everyone in our class. Then they said, "This proves that our class loves pizza the most." Why are they wrong?''', 'Child explains that age data cannot answer a question about food preferences.', 'Child agrees with the friend, or is confused.', 'What kind of data would you need to collect to prove what the class loves to eat?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L3_B', 'P2c', 3, 'B', 'Error detection', NULL, 'Say: ''I want to know who the fastest runner is. So I measured how tall everyone is. Did I answer my question? Why?''', 'Child explains that height does not equal speed, so the data doesn''t answer the question.', 'Child thinks tall people are always faster.', 'What should I have measured instead?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L3_C', 'P2c', 3, 'C', 'Error detection', NULL, 'Show a list: ''Apples: 5, Bananas: 3''. Say: ''Someone looked at this and asked: Are the apples red or green? Can this list tell them? Why?''', 'Child explains the list only gives the number of apples, not their color.', 'Child assumes a color based on the fruit name.', 'If you wanted to know the color, how would you change the list?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_A', 'P2c', 4, 'A', 'Design and Justification', NULL, 'Say: ''Think of a question about our family that you don''t know the answer to. Tell me the question, and then tell me exactly what data you would need to collect to answer it.''', 'Child formulates a measurable question (e.g., ''Who sleeps the longest?'') and an appropriate data collection method (recording sleep times).', 'Child asks an unmeasurable question (''Who is the best?''), or cannot link it to data.', 'If you collected the data and two people had the exact same answer, what does that tell you?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_B', 'P2c', 4, 'B', 'Design and Justification', NULL, 'Say: ''Create a short list of data (just 3 numbers and labels) that answers the question: What is the most common shoe size in this house?''', 'Child creates relevant data, e.g., ''Size 3: 2 pairs. Size 8: 1 pair. Size 10: 1 pair.''', 'Child lists random items or numbers unrelated to shoe sizes.', 'Why must you include the labels (like ''Size 3'') and not just the numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_C', 'P2c', 4, 'C', 'Design and Justification', NULL, 'Say: ''Teach me why we need to ask the RIGHT question before we start counting things.''', 'Child explains that if you count the wrong things (like counting colors when you want to know sizes), your numbers are useless.', 'Child cannot articulate the connection between the goal and the method.', 'Can you give me an example of counting the wrong thing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2c_L4_M', 'P2c', 4, 'M', 'Real-world situation', NULL, 'We found a box of old keys. You want to figure out which room has the most doors. Can counting these keys tell you that?', 'Child realizes keys do not equal doors, and that the keys might go to locks, cars, or other houses. The data doesn''t answer the question.', 'Child assumes more keys means more doors.', 'What is the only way to truly find out which room has the most doors?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L1_A', 'P2d', 1, 'A', 'Physical grouping', 'A handful of coins or small mixed items, Paper', 'Put the coins in a pile. Say: ''Sort these by size. Which pile is the biggest? Without counting, just point to the group that has the most in it.''', 'Child visually identifies the largest group after sorting.', 'Child points to the largest coin instead of the largest group, or guesses without sorting.', 'If you put the biggest pile next to the smallest pile, what do you notice?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L1_B', 'P2d', 1, 'B', 'Physical grouping', 'Cards or pictures (e.g., 3 dogs, 1 cat, 4 birds)', 'Lay the cards out randomly. Say: ''Group all the same animals together. Which animal showed up the most often?''', 'Child correctly groups the cards and identifies the birds as the most frequent.', 'Child groups them incorrectly or guesses.', 'If I hide one bird card, which animal shows up the most often now?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L1_C', 'P2d', 1, 'C', 'Physical grouping', 'Mismatched socks from the laundry', 'Give the child a pile of socks (e.g., 5 white, 2 black, 1 striped). Say: ''Sort these by color. Which color do we have the most of right here?''', 'Child sorts by color and correctly identifies white as the most common.', 'Child tries to match pairs instead of grouping all similar colors, or guesses without sorting.', 'Why is it easier to find out which color is most common by sorting them first?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L2_A', 'P2d', 2, 'A', 'Finding mode from a list', NULL, 'Show a list of numbers: 2, 5, 2, 8, 2, 1. Say: ''Which number is in this list the most times?''', 'Child identifies 2 as the most frequent number.', 'Child points to 8 because it is the largest value, or guesses.', 'How can you prove that 2 is there more times than 5?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L2_B', 'P2d', 2, 'B', 'Finding mode from a tally chart', NULL, 'Show a tally chart: Apples (II), Bananas (IIII), Grapes (I). Say: ''Which fruit is the most popular according to the tallies?''', 'Child identifies Bananas by finding the category with the most tally marks.', 'Child counts incorrectly or picks the first item.', 'How did you know without counting every single mark?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L2_C', 'P2d', 2, 'C', 'Finding mode from a bar graph', NULL, 'Show a simple bar graph (e.g., Cats: 3, Dogs: 5, Birds: 2). Say: ''Which bar is the tallest? What animal does that bar stand for?''', 'Child identifies the tallest bar and reads the corresponding label (Dogs) at the bottom.', 'Child identifies the highest number on the axis rather than the category, or misreads the label.', 'If the Birds bar grew to be exactly as tall as the Dogs bar, which one would be the most popular?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L3_A', 'P2d', 3, 'A', 'Error detection', NULL, 'Show a list: 3, 8, 3, 5, 3. Say: ''My friend says 8 is the most popular number because it is the biggest. Are they right? Why or why not?''', 'Child explains the difference between ''the biggest value'' and ''the value that appears most often''.', 'Child agrees with the friend.', 'Can you have a list where a tiny number like 1 is the most popular?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L3_B', 'P2d', 3, 'B', 'Error detection', NULL, 'Show a list: 2, 4, 6, 8. Say: ''What number appears most often here?''', 'Child recognizes that all numbers appear exactly once, so there is no single number that appears most often.', 'Child picks a random number or the biggest one.', 'If I add another 4 to the list, what happens?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L3_C', 'P2d', 3, 'C', 'Error detection', NULL, 'Show a tally chart where two categories tie: Red (III), Blue (III). Say: ''My friend says Red won because it is first on the list. Is that fair?''', 'Child explains that it is a tie because both have the same number of marks.', 'Child agrees because Red is listed first.', 'What would you have to do to break the tie?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_A', 'P2d', 4, 'A', 'Design and Justification', NULL, 'Say: ''Create a list of 5 numbers where 7 is the number that shows up the most often.''', 'Child generates a list like 7, 2, 7, 4, 7.', 'Child creates a list with no repeats, or where another number appears more often.', 'How could you change your list so that 7 is NO LONGER the number that shows up most often?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_B', 'P2d', 4, 'B', 'Design and Justification', NULL, 'Say: ''Imagine a race with 10 cars. Only red and blue cars are racing. Tell me a story about the cars crossing the finish line so that Red is the most common color to finish.''', 'Child creates a scenario where more than 5 red cars finish, e.g., ''6 red cars finish, and 4 blue cars finish.''', 'Child tells a story where blue wins or where the total is wrong.', 'If exactly 5 red and 5 blue cars cross the line, what happens to the most common color?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_C', 'P2d', 4, 'C', 'Design and Justification', NULL, 'Say: ''Draw a very simple bar graph with 3 bars where two of the bars tie for being the tallest.''', 'Child draws a graph with labels and ensures two bars are exactly the same height and taller than the third.', 'Child forgets labels, makes all bars different, or makes the tie shorter than the third bar.', 'If you asked one more person to vote, could there still be a tie?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2d_L4_M', 'P2d', 4, 'M', 'Real-world situation', NULL, 'You are in charge of buying new shoes for your soccer team. You look at everyone''s current shoes: Size 4, Size 5, Size 4, Size 6, Size 4. You can only afford to buy ONE extra pair just in case someone''s breaks. What size should you buy and why?', 'Child identifies Size 4 because it is the most common size worn by the team.', 'Child picks the largest size, or a random size.', 'If three more kids join and they all wear Size 6, what size should you buy as the backup then?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L1_A', 'P2e', 1, 'A', 'Physical sorting', 'Cards with events (e.g., Sun rising, raining frogs, eating lunch)', 'Show the cards. Say: ''Sort these into two piles: Things that are very likely to happen tomorrow, and things that are very unlikely to happen tomorrow.''', 'Child correctly categorizes everyday events vs absurd or rare events.', 'Child thinks impossible events are likely, or puts everything in one pile.', 'Is ''raining frogs'' just unlikely, or is it actually impossible?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L1_B', 'P2e', 1, 'B', 'Physical sorting', 'A bag, 10 red blocks, 1 blue block', 'Put the blocks in the bag and shake it. Say: ''If I close my eyes and pull out one block, am I likely to get a red one or a blue one?''', 'Child identifies red as the likely outcome because there are many more of them.', 'Child guesses blue because it is their favorite color.', 'If I want to make pulling a blue block likely, what do I need to do to the bag?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L1_C', 'P2e', 1, 'C', 'Physical sorting', 'A spinner with unequal sections (e.g., 3/4 red, 1/4 blue)', 'Show the spinner. Say: ''Spin this 5 times. Before you spin, which color is more likely to win?''', 'Child predicts the larger section (red) will win.', 'Child thinks the small section is just as likely to win.', 'If you spin and it lands on blue, does that mean the spinner is broken?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L2_A', 'P2e', 2, 'A', 'Categorizing probability', NULL, 'Say: ''I am going to read a sentence. Tell me if it is Certain, Likely, Unlikely, or Impossible: You will drink water sometime this week.''', 'Child categorizes the statement as ''Certain'' (or very likely depending on the child''s interpretation, but ''Certain'' is technically correct for biological needs over a week).', 'Child says Impossible or Unlikely.', 'Why isn''t it just ''likely''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L2_B', 'P2e', 2, 'B', 'Categorizing probability', NULL, 'Show a bag with 9 green marbles and 1 yellow marble. Say: ''Is pulling a green marble likely, unlikely, or certain?''', 'Child identifies ''Likely''.', 'Child says ''Certain'' (forgetting the yellow marble) or ''Unlikely''.', 'Why isn''t it ''Certain''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L2_C', 'P2e', 2, 'C', 'Categorizing probability', NULL, 'Show a spinner that is half red, half blue. Say: ''Is spinning red likely, unlikely, or equally likely as spinning blue?''', 'Child identifies ''Equally likely''.', 'Child guesses one color over the other.', 'If I color a little more of the spinner red, what happens to the chances?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L3_A', 'P2e', 3, 'A', 'Error detection', NULL, 'Say: ''My friend bought one lottery ticket. They said, "I am likely to win because there are only two choices: win or lose." Are they right? Why?''', 'Child explains that ''two choices'' does not mean ''equally likely'', and losing is much more likely because there are millions of losing tickets.', 'Child agrees with the friend.', 'If there is 1 winning ticket and 100 losing tickets, is it still a 50/50 chance?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L3_B', 'P2e', 3, 'B', 'Error detection', NULL, 'Show a bag with 5 red blocks and 5 blue blocks. Say: ''My friend reached in 3 times and pulled out a red block every time. They say, "The bag must have more red blocks." Are they right? Why?''', 'Child explains that it is possible to pull the same color multiple times even if the amounts are equal, so the friend isn''t necessarily right.', 'Child agrees with the friend.', 'If they pulled 100 blocks, do you think they would all be red?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L3_C', 'P2e', 3, 'C', 'Error detection', NULL, 'Show a picture of a six-sided die. Say: ''Someone says it is impossible to roll a 7. Is that true? Why?''', 'Child confirms it is true because the numbers only go up to 6.', 'Child thinks a 7 can be rolled if they throw it hard enough.', 'What would you have to do to the dice to make rolling a 7 possible?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_A', 'P2e', 4, 'A', 'Design and Justification', NULL, 'Say: ''Tell me something that is impossible to happen today, and something that is certain to happen today.''', 'Child generates two accurate statements demonstrating understanding of the extremes of probability.', 'Child confuses likely/unlikely with certain/impossible.', 'If you say ''The sun will shine today'', is that certain or just likely?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_B', 'P2e', 4, 'B', 'Design and Justification', NULL, 'Say: ''Draw a spinner with three colors: Red, Blue, and Green. Make it so that spinning Red is very likely, spinning Blue is unlikely, and spinning Green is impossible.''', 'Child draws a spinner mostly Red, a small sliver of Blue, and no Green section.', 'Child draws equal sections, or includes Green.', 'How would you change the drawing to make Blue and Red equally likely?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_C', 'P2e', 4, 'C', 'Design and Justification', NULL, 'Say: ''Make up a game with a coin where you have an unfair advantage over me. Explain the rules.''', 'Child creates rules where their winning condition has higher probability (e.g., ''If it lands heads OR tails, I win. If it lands on its edge, you win.'').', 'Child creates a fair game (e.g., heads I win, tails you win), or impossible rules.', 'How would you fix the game to make it fair for both of us?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2e_L4_M', 'P2e', 4, 'M', 'Real-world situation', NULL, 'You are planning a picnic for Saturday. The weather report says there is a 90% chance of heavy rain. Should you plan to have the picnic outside or inside? Why?', 'Child chooses inside because heavy rain is very likely.', 'Child chooses outside because they like picnics, ignoring the high probability of rain.', 'If the report said there was a 10% chance of rain, would you change your mind? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L1_A', 'P2f', 1, 'A', 'Physical experiment', 'A coin, Paper, Pencil', 'Say: ''Flip this coin 10 times. Draw a tally mark for each Head and each Tail you get.''', 'Child successfully completes the physical experiment and records the 10 results.', 'Child predicts the outcome without flipping, loses count, or records incorrectly.', 'Did you get exactly 5 Heads and 5 Tails? Why or why not?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L1_B', 'P2f', 1, 'B', 'Physical experiment', 'A 6-sided die, Paper, Pencil', 'Say: ''Roll the die 6 times. Write down the numbers you roll.''', 'Child completes the rolling and accurately records the 6 numbers.', 'Child expects to get 1, 2, 3, 4, 5, 6 in order or stops after fewer rolls.', 'Did you roll every number from 1 to 6? Why do you think that happened?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L1_C', 'P2f', 1, 'C', 'Physical experiment', 'A bag, 3 red blocks, 1 blue block, Paper, Pencil', 'Put the blocks in the bag. Say: ''Without looking, pull a block out, write down its color, and put it back. Do this 5 times.''', 'Child pulls, records, replaces the block, and repeats 5 times.', 'Child doesn''t replace the block, altering the probability for subsequent pulls.', 'Why is it important to put the block back in the bag every time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L2_A', 'P2f', 2, 'A', 'Analyzing experiment data', NULL, 'Say: ''I flipped a coin 20 times. Here are my results: 14 Heads, 6 Tails. Did I get the expected 10 Heads and 10 Tails?''', 'Child correctly identifies that the results were not 10 and 10, recognizing variance.', 'Child thinks the coin must be broken or rigged.', 'If you flipped a coin 100 times, do you think you would get exactly 50 Heads?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L2_B', 'P2f', 2, 'B', 'Analyzing experiment data', NULL, 'Show a tally chart for rolling a die 12 times: 1 (II), 2 (I), 3 (IIII), 4 (II), 5 (I), 6 (II). Say: ''Which number was rolled the most? Which the least?''', 'Child identifies 3 as most (4 rolls) and 2 or 5 as least (1 roll).', 'Child identifies 6 as most because it''s the highest number on the die.', 'Why didn''t every number get rolled 2 times?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L2_C', 'P2f', 2, 'C', 'Analyzing experiment data', NULL, 'Say: ''I pulled a block from a bag 10 times, replacing it each time. I got Red 8 times and Blue 2 times. If you reached in, what color do you think you would probably get?''', 'Child infers that Red is the most likely color in the bag and predicts pulling Red.', 'Child predicts Blue, or cannot articulate why Red is more likely.', 'Are you absolutely certain you will pull a Red block next time?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L3_A', 'P2f', 3, 'A', 'Error detection', NULL, 'Say: ''My friend flipped a coin 5 times and got Heads every time. They say the 6th flip WILL definitely be Tails because it''s "due". Why is this wrong?''', 'Child explains that the coin does not have a memory, so the chance is still equal.', 'Child agrees with the friend.', 'Does the coin remember what it did before?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L3_B', 'P2f', 3, 'B', 'Error detection', NULL, 'Say: ''We rolled a die 6 times and never rolled a 4. My friend said, "The die is broken! It should have landed on 4 once!" Are they right? Why?''', 'Child explains that rolling each number exactly once in 6 rolls is unlikely, and variance is normal.', 'Child thinks the die must be flawed.', 'If you rolled it 100 times, do you think a 4 would show up?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L3_C', 'P2f', 3, 'C', 'Error detection', NULL, 'Show a bag of 5 red blocks and 1 blue block. Say: ''My friend pulled a blue block on their first try! They said, "Wow, blue must be the most common color in the bag." Why are they wrong?''', 'Child points out that pulling a rare color on the first try is possible, but it doesn''t change the actual amount in the bag.', 'Child agrees with the friend''s conclusion based on the single pull.', 'If they pulled 10 more blocks, what color do you think they would mostly get?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_A', 'P2f', 4, 'A', 'Design and Justification', NULL, 'Say: ''Design a simple experiment using a coin to decide who gets to go first in a game. Then play it out to show me the result.''', 'Child assigns Heads to one person and Tails to another, flips the coin, and declares the winner.', 'Child flips the coin without assigning outcomes, or creates an unfair rule.', 'If the coin lands on the floor and you can''t see it, what should you do?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_B', 'P2f', 4, 'B', 'Design and Justification', NULL, 'Say: ''Make up an experiment with a six-sided die where I have a likely chance of winning, and you have an unlikely chance of winning.''', 'Child creates rules such as ''If it lands on 1, 2, 3, 4, or 5, you win. If it lands on 6, I win.''', 'Child creates a fair game (e.g., odds vs evens) or an impossible game.', 'How many winning numbers do you have compared to my winning numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_C', 'P2f', 4, 'C', 'Design and Justification', NULL, 'Say: ''Explain why flipping a coin 100 times gives you a better idea of what to expect than flipping it just 2 times.''', 'Child explains that small amounts of flips can have streaks, but more flips show the true, steady pattern (closer to half and half).', 'Child cannot articulate the difference, saying it''s just ''more work''.', 'If you flip it twice and get 2 Heads, does that mean the coin ONLY lands on Heads?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2f_L4_M', 'P2f', 4, 'M', 'Real-world situation', NULL, 'You and your friend both want to sit in the front seat of the car. You suggest flipping a coin: ''Heads I win, Tails I win.'' Is that a fair way to decide? Why or why not?', 'Child recognizes the trick and states it is unfair because the friend has zero chance of winning.', 'Child agrees, missing the linguistic trick.', 'What rule would make it exactly fair for both of you?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L1_A', 'P2g', 1, 'A', 'Physical comparison', 'Two handfuls of coins or small items (one large pile, one small pile)', 'Show the two piles. Say: ''Pile A is my money. Pile B is your money. Without counting, whose pile looks like it has more? Now count them to prove it.''', 'Child visually estimates correctly, then verifies by counting and comparing the two totals.', 'Child counts but cannot articulate which is larger, or miscounts significantly.', 'Did the larger looking pile actually have more when you counted it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L1_B', 'P2g', 1, 'B', 'Physical comparison', 'Two short lists of family/friends (e.g., ''People who like dogs'', ''People who like cats'')', 'Show the lists. Say: ''Look at the names under Dogs and the names under Cats. Which list is longer? Who has more people on their side?''', 'Child compares the physical length of the lists or counts the names to determine the larger group.', 'Child guesses or focuses on a specific name.', 'If I add your name to the shorter list, which list has more people now?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L1_C', 'P2g', 1, 'C', 'Physical comparison', 'Two small groups of objects representing votes (e.g., 5 red blocks for ''Pizza'', 3 blue blocks for ''Burger'')', 'Set up the blocks. Say: ''The red blocks are votes for Pizza. The blue blocks are votes for Burgers. Which food got more votes?''', 'Child visually compares the groups and correctly identifies the larger one.', 'Child guesses or misinterprets the colors.', 'How many more votes did Pizza get than Burgers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L2_A', 'P2g', 2, 'A', 'Comparing tally charts', NULL, 'Show two tally charts. Chart 1 (Class A): Dogs(III), Cats(II). Chart 2 (Class B): Dogs(II), Cats(IIII). Say: ''Which class liked Dogs more?''', 'Child reads both charts and identifies Class A (3 vs 2).', 'Child looks at only one chart, or miscounts tallies.', 'Which class liked Cats more?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L2_B', 'P2g', 2, 'B', 'Comparing bar graphs', NULL, 'Show two simple bar graphs side-by-side. Graph 1 (Monday): Apples(4), Oranges(2). Graph 2 (Tuesday): Apples(1), Oranges(5). Say: ''On which day were more apples eaten?''', 'Child reads the ''Apples'' bar on both graphs and identifies Monday.', 'Child looks at the tallest bar overall (Oranges on Tuesday), instead of the specific category requested.', 'On which day were more oranges eaten?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L2_C', 'P2g', 2, 'C', 'Comparing totals from data', NULL, 'Show two lists. Group 1: 3 boys, 4 girls. Group 2: 5 boys, 1 girl. Say: ''Which group has more children in total?''', 'Child adds the numbers for each group (3+4=7, 5+1=6) and identifies Group 1 as larger.', 'Child picks Group 2 because 5 is the biggest single number.', 'How did you find the total for each group before comparing them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L3_A', 'P2g', 3, 'A', 'Error detection', NULL, 'Show two lists. Class A asked 10 kids: 6 like Red, 4 like Blue. Class B asked 100 kids: 50 like Red, 50 like Blue. Say: ''My friend says Red is more popular in Class B because 50 is bigger than 6. Are they right? Why?''', 'Child explains that 50 out of 100 is half, while 6 out of 10 is more than half, so Red is more popular *in proportion* in Class A.', 'Child agrees with the friend based only on the raw numbers.', 'If Class A had asked 100 kids, and they all answered the same way, how many would like Red?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L3_B', 'P2g', 3, 'B', 'Error detection', NULL, 'Show two bar graphs with different scales. Graph 1 (scale by 1s) shows a bar reaching the top line (value 5). Graph 2 (scale by 10s) shows a short bar (value 20). Say: ''My friend says the first graph has more because the bar is taller. Why are they wrong?''', 'Child explains that the scale numbers determine the value, not just the physical height of the bar.', 'Child agrees that the taller bar means more.', 'What number should you look at to find out exactly how much each bar represents?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L3_C', 'P2g', 3, 'C', 'Error detection', NULL, 'Show a tally chart for Class A (10 votes total) and Class B (5 votes total). Say: ''My friend compared these two classes and decided Class A likes Pizza more than Class B. But they asked twice as many people in Class A! Is this a fair comparison? Why?''', 'Child recognizes that differing sample sizes can distort straight comparisons.', 'Child thinks the comparison is fair.', 'How could you make the comparison fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_A', 'P2g', 4, 'A', 'Design and Justification', NULL, 'Say: ''Create two short lists of data (e.g., votes for games) for two different teams, where Team A has a higher total number of votes, but Team B has more votes for a specific game (like Tag).'' ', 'Child constructs data satisfying both conditions.', 'Child creates data that violates one or both conditions, or uses abstract numbers without context.', 'How did you make sure Team B had more votes for Tag even though Team A had more total votes?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_B', 'P2g', 4, 'B', 'Design and Justification', NULL, 'Say: ''Draw two simple bar graphs next to each other that look identical, but tell me a story about why the first graph actually represents a much larger number than the second graph.''', 'Child explains that the scales on the sides of the graphs would be different (e.g., one goes by 1s, the other by 100s).', 'Child cannot explain how identical bars can represent different amounts.', 'Where on the graph do you write the numbers that change the scale?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_C', 'P2g', 4, 'C', 'Design and Justification', NULL, 'Say: ''Teach me the steps for comparing two different tally charts to find out which chart has the highest single category overall.''', 'Child explains a systematic process of finding the highest tally in chart A, then finding the highest tally in chart B, and finally comparing those two numbers.', 'Child gives a confusing or incomplete explanation, or suggests guessing.', 'What if the highest category in Chart A is a tie? How does that change your steps?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2g_L4_M', 'P2g', 4, 'M', 'Real-world situation', NULL, 'Two classes are collecting cans for recycling. Class A collected 2 bags, and Class B collected 4 boxes. Class B is celebrating because they think they collected more. What do they need to know before they celebrate?', 'Child points out that they need to know how many cans are in a bag versus a box (the units/amounts are not directly comparable).', 'Child agrees Class B won because 4 is more than 2.', 'If one box holds 10 cans, and one bag holds 50 cans, who actually collected more?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

